function () {
  var cart, items, i, li, pid, vid, qty, price;
  try {
    cart =
      (window.meta && window.meta.cart) ||
      (window.ShopifyAnalytics && window.ShopifyAnalytics.meta && window.ShopifyAnalytics.meta.cart);
    if (!cart || !cart.items || !cart.items.length) return [];

    var digits = function (x) { return String(x == null ? "" : x).replace(/\D/g, ""); };
    var asNum = function (x) { var n = Number(x); return isFinite(n) ? n : 0; };

    items = [];
    for (i = 0; i < cart.items.length; i++) {
      li = cart.items[i] || {};
      pid = digits(li.product_id || li.productId || li.product_id);
      vid = digits(li.variant_id || li.variantId || li.variant_id);
      qty = asNum(li.quantity);
      price = asNum(li.price);
      if (price > 1000) price = price / 100;

      if (!pid || !vid || !qty) continue;

      items.push({
        item_id: "shopify_US_" + pid + "_" + vid,
        item_name: li.product_title || li.title || undefined,
        quantity: qty,
        price: price || undefined
      });
    }

    return items.length ? items : [];
  } catch (e) {
    return [];
  }
}

function() {
  var host = location.hostname || "";
  var path = location.pathname || "";

  // Subdomain-based presales
  if (host.indexOf("edu.") === 0) return "presale";
  if (host.indexOf("articles.") === 0) return "presale";
  if (host.indexOf("blog.") === 0) return "presale";

  // PRODUCT FIRST (critical for Shopify)
  if (path.indexOf("/products/") !== -1) return "product";

  // Then collections
  if (path.indexOf("/collections/") !== -1) return "collection";

  // Other page types
  if (path === "/" || path === "") return "home";
  if (path.indexOf("/pages/") === 0) return "page";
  if (path === "/cart") return "cart";
  if (path.indexOf("/checkouts/") === 0) return "checkout";
  if (path.indexOf("/post-purchase") !== -1) return "post_purchase";
  if (path.indexOf("/thank-you") !== -1) return "thank_you";

  return "unknown";
}

function () {
  var el, id, name, slot;
  try {
    el = document.querySelector("[data-promo-id]");
    if (!el) return [];

    id = el.getAttribute("data-promo-id");
    name = el.getAttribute("data-promo-name");
    slot = el.getAttribute("data-promo-slot");

    if (!id || !name) return [];

    return [{
      promotion_id: id,
      promotion_name: name,
      creative_slot: slot || undefined
    }];
  } catch (e) {
    return [];
  }
}

function(){
  function getCookie(name){
    try{
      var m=document.cookie.match(new RegExp('(?:^|; )'+name.replace(/([.$?*|{}()\[\]\\\/\+^])/g,'\\$1')+'=([^;]*)'));
      return m ? decodeURIComponent(m[1]) : '';
    }catch(e){return '';}
  }
  var v = getCookie('th_vid');
  if (!v) { try{ v = localStorage.getItem('th_vid') || ''; }catch(e){} }
  if (!v && window.th_vid) v = window.th_vid;
  return v || '';
}

function () {
  var p, variants, v, selectedVid, pid, vid, handle;
  var rawPrice, price, rawCompare, compareAt, discount;
  try {
    p = (window.meta && window.meta.product) ||
        (window.ShopifyAnalytics && window.ShopifyAnalytics.meta && window.ShopifyAnalytics.meta.product);
    if (!p) return [];

    var asNum = function (x) {
      var n = Number(x);
      return isFinite(n) ? n : 0;
    };

    var digits = function (x) {
      return String(x == null ? "" : x).replace(/\D/g, "");
    };

    var getSelectedVariantId = function () {
      var m, el;
      try {
        m = (location.search || "").match(/[?&]variant=(\d+)/);
        if (m && m[1]) return m[1];
      } catch (_e) {}

      try {
        el = document.querySelector('form[action*="/cart/add"] [name="id"]');
        if (el && el.value) return String(el.value);
      } catch (_e2) {}

      return "";
    };

    selectedVid = getSelectedVariantId();
    variants = p.variants || [];
    v = null;

    if (selectedVid) {
      for (var i = 0; i < variants.length; i++) {
        if (String(variants[i].id) === String(selectedVid)) { v = variants[i]; break; }
      }
    }
    if (!v) v = variants[0];
    if (!v) return [];

    pid = digits(p.id);
    vid = digits(v.id);

    rawPrice = v.price;
    price = asNum(rawPrice);
    if (price > 1000) price = price / 100;

    rawCompare = v.compare_at_price;
    compareAt = asNum(rawCompare);
    if (compareAt > 1000) compareAt = compareAt / 100;

    discount = 0;
    if (compareAt > price) discount = compareAt - price;

    handle = p.handle || "";
    var itemListName = handle ? handle : undefined;
    var itemListId = (handle && vid) ? (handle + "_" + vid) : undefined;

    var currency =
      (window.Shopify && window.Shopify.currency && window.Shopify.currency.active)
        ? window.Shopify.currency.active
        : "USD";

    return [{
      item_id:       (pid && vid) ? ("shopify_US_" + pid + "_" + vid) : undefined,
      item_group_id: pid ? ("shopify_US_" + pid) : undefined,
      variant_id:    vid || undefined,
      sku:           (v.sku != null && String(v.sku).trim()) ? String(v.sku).trim() : undefined,

      item_name:     p.title || undefined,
      item_brand:    "Terra Health Essentials",
      item_variant:  v.public_title || v.name || undefined,

      affiliation:   "Shopify Web Store",
      currency:      currency,
      price:         price || undefined,
      quantity:      1,

      item_list_name: itemListName,
      item_list_id:   itemListId,

      discount:      discount ? discount : undefined,
      coupon:        undefined,
      index:         1,

      item_category:  (p.type || undefined),
      item_category2: undefined,
      item_category3: undefined,
      item_category4: undefined,
      item_category5: undefined,

      location_id:    undefined,
      creative_name:  undefined,
      creative_slot:  undefined,
      promotion_id:   undefined,
      promotion_name: undefined
    }];
  } catch (e) {
    return [];
  }
}

function() {
  var items = [];
  var nodes, i, n;
  var digits = function (x) { return String(x == null ? "" : x).replace(/\D/g, ""); };

  nodes = document.querySelectorAll("[data-product-id][data-variant-id][data-product-name][data-product-price]");
  for (i = 0; i < nodes.length; i++) {
    n = nodes[i];

    var pid = digits(n.getAttribute("data-product-id"));
    var vid = digits(n.getAttribute("data-variant-id"));
    var name = n.getAttribute("data-product-name");
    var price = Number(n.getAttribute("data-product-price"));

    if (!pid || !vid || !name || !isFinite(price)) continue;

    items.push({
      item_id: "shopify_US_" + pid + "_" + vid,
      item_name: name,
      index: i + 1,
      price: price
    });
  }

  return items.length ? items : undefined;
}
